// Wallapop – transform: respuestas /api/v3/search (category_ids=100) → items cat 100 → UPSERT
// Maneja varias páginas acumuladas (paginación integrada del HTTP node): $input.all()
const inputs = $input.all();

function normalizeFuel(raw) {
  const s = String(raw || '').toLowerCase();
  if (s.indexOf('dies') !== -1 || s.indexOf('dié') !== -1 || s.indexOf('diã') !== -1) return 'Diesel';
  const ench = (s.indexOf('enchufable') !== -1 || s.indexOf('plug') !== -1) && s.indexOf('no enchufable') === -1;
  if (s.indexOf('hibrido') !== -1 || s.indexOf('híbrido') !== -1 || s.indexOf('hybrid') !== -1) return ench ? 'Híbrido enchufable' : 'Híbrido';
  if (s.indexOf('eléctrico') !== -1 || s.indexOf('electrico') !== -1 || s.indexOf('electric') !== -1) return 'Eléctrico';
  if (s.indexOf('gasolina') !== -1 || s.indexOf('petrol') !== -1) return 'Gasolina';
  if (s.indexOf('glp') !== -1 || s.indexOf('gnc') !== -1 || s.indexOf('gas') !== -1) return 'Gas';
  return raw || '';
}
function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'number') return isNaN(v) ? 'NULL' : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}

let raw = [];
for (const inp of inputs) {
  const body = inp.json || {};
  const items = (body.data && body.data.section && body.data.section.payload && body.data.section.payload.items) || [];
  raw = raw.concat(items);
}

// dedupe por id + solo coches (cat 100 con atributos)
const seen = {};
const cars = [];
for (const it of raw) {
  if (Number(it.category_id) !== 100) continue;
  const ta = it.type_attributes;
  if (!ta) continue;
  if (seen[it.id]) continue;
  seen[it.id] = 1;
  cars.push(it);
}

if (!cars.length) return [{ json: { sql: null, count: 0 } }];

const rows = [];
for (const it of cars) {
  const ta = it.type_attributes || {};
  const id = 'wp_' + String(it.id);
  const url = it.web_slug ? ('https://es.wallapop.com/item/' + it.web_slug) : '';
  const brand = ta.brand || '';
  const model = ta.model || '';
  const version = ta.version || '';
  const title = it.title || (brand + ' ' + model).trim();
  const year = (ta.year != null && ta.year > 1900) ? String(ta.year) : 'NULL';
  const mileage = (ta.km != null) ? String(parseInt(ta.km, 10)) : 'NULL';
  const price = (it.price && it.price.amount != null) ? String(Math.round(it.price.amount)) : 'NULL';
  const fuel = normalizeFuel(ta.engine);
  const powerCv = (ta.horsepower != null && ta.horsepower > 0) ? Math.round(ta.horsepower) : null;
  const powerKw = powerCv ? Math.round(powerCv / 1.35962) : null;

  const imgs = Array.isArray(it.images) ? it.images.map(function (im) { return im && im.urls ? (im.urls.big || im.urls.medium || im.urls.small) : null; }).filter(Boolean).slice(0, 15) : [];
  const imageUrl = imgs[0] || '';
  const imagesJson = JSON.stringify(imgs).replace(/'/g, "''");
  const loc = it.location || {};
  const city = loc.city || '';
  const province = loc.region2 || loc.region || '';
  const sellerType = it.is_top_profile ? 'profesional' : 'particular';

  const row = '(' +
    esc(id) + ", 'wallapop', " + esc(url) + ', ' + esc(title) + ', ' + esc(brand) + ', ' + esc(model) + ', ' + esc(version) + ', ' +
    year + ', ' + mileage + ', ' + price + ', ' +
    esc(fuel) + ', ' +
    esc(imageUrl) + ", '" + imagesJson + "', " +
    esc(city) + ', ' + esc(province) + ', ' + esc(city) + ', ' +
    "'" + sellerType + "', 'compra', " +
    (powerCv !== null ? String(powerCv) : 'NULL') + ', ' + (powerKw !== null ? String(powerKw) : 'NULL') +
    ', NOW(), NOW(), NOW()' +
  ')';
  rows.push(row);
}

const cols = 'id, portal, url, title, brand, model, version, year, mileage, price, fuel, image_url, images, city, province, location, seller_type, listing_type, power_cv, power_kw, first_seen_at, scraped_at, last_seen_at';

const onConflict = 'ON CONFLICT (id) DO UPDATE SET ' +
  'url = EXCLUDED.url, title = EXCLUDED.title, price = EXCLUDED.price, mileage = EXCLUDED.mileage, ' +
  "image_url = COALESCE(NULLIF(moveadvisor_market_offers.image_url,''), EXCLUDED.image_url), " +
  "images = COALESCE(NULLIF(moveadvisor_market_offers.images,''), EXCLUDED.images), " +
  'power_cv = COALESCE(EXCLUDED.power_cv, moveadvisor_market_offers.power_cv), ' +
  'power_kw = COALESCE(EXCLUDED.power_kw, moveadvisor_market_offers.power_kw), ' +
  'last_seen_at = NOW(), updated_at = NOW()';

const sql = 'INSERT INTO moveadvisor_market_offers (' + cols + ') VALUES ' + rows.join(', ') + ' ' + onConflict;
return [{ json: { sql: sql, count: rows.length } }];
